@Composable
fun MainApp(
    uiState: ReadingUiState,
    onPalmCaptured: (String) -> Unit,
    onReset: () -> Unit
) {
    Box(
        modifier = Modifier
            .fillMaxSize()
            .background(
                Brush.verticalGradient(
                    colors = listOf(DeepPurple, Color(0xFF0F0C29), Color(0xFF302B63))
                )
            )
    ) {
        when (uiState) {
            is ReadingUiState.Idle -> {
                CameraScreen(onPalmMetadataReady = onPalmCaptured)
                // Overlay hint text
                Box(modifier = Modifier.fillMaxSize(), contentAlignment = Alignment.BottomCenter) {
                    Card(
                        modifier = Modifier.padding(24.dp),
                        shape = RoundedCornerShape(20.dp),
                        colors = CardDefaults.cardColors(containerColor = CardDark.copy(alpha = 0.85f))
                    ) {
                        Text(
                            text = "✋  Apna haath camera ke saamne rakhein\nAI aapki rekhaon ko padhega",
                            modifier = Modifier.padding(20.dp),
                            color = SoftWhite,
                            fontSize = 16.sp,
                            textAlign = TextAlign.Center
                        )
                    }
                }
            }
            is ReadingUiState.Loading -> {
                Column(
                    modifier = Modifier.fillMaxSize(),
                    verticalArrangement = Arrangement.Center,
                    horizontalAlignment = Alignment.CenterHorizontally
                ) {
                    CircularProgressIndicator(color = GoldAccent)
                    Spacer(modifier = Modifier.height(16.dp))
                    Text(
                        text = "🔮 AI aapki rekhaon ko padh raha hai...",
                        color = SoftWhite,
                        fontSize = 18.sp,
                        fontWeight = FontWeight.Medium
                    )
                }
            }
            is ReadingUiState.Success -> {
                Column(
                    modifier = Modifier
                        .fillMaxSize()
                        .padding(24.dp),
                    horizontalAlignment = Alignment.CenterHorizontally
                ) {
                    Text(
                        text = "✨ Aapka Haath Padha Gaya",
                        color = GoldAccent,
                        fontSize = 24.sp,
                        fontWeight = FontWeight.Bold
                    )
                    Spacer(modifier = Modifier.height(16.dp))
                    Card(
                        modifier = Modifier
                            .fillMaxWidth()
                            .weight(1f),
                        colors = CardDefaults.cardColors(containerColor = CardDark),
                        shape = RoundedCornerShape(16.dp)
                    ) {
                        Text(
                            text = uiState.reading,
                            modifier = Modifier.padding(16.dp),
                            color = SoftWhite,
                            fontSize = 15.sp
                        )
                    }
                    Spacer(modifier = Modifier.height(16.dp))
                    Button(
                        onClick = onReset,
                        colors = ButtonDefaults.buttonColors(containerColor = NeonViolet)
                    ) {
                        Text("Dobara Scan Karein", color = SoftWhite)
                    }
                }
            }
            is ReadingUiState.Error -> {
                Column(
                    modifier = Modifier.fillMaxSize(),
                    verticalArrangement = Arrangement.Center,
                    horizontalAlignment = Alignment.CenterHorizontally
                ) {
                    Text(
                        text = "❌ Error: ${uiState.message}",
                        color = Color.Red,
                        fontSize = 16.sp,
                        textAlign = TextAlign.Center,
                        modifier = Modifier.padding(16.dp)
                    )
                    Button(
                        onClick = onReset,
                        colors = ButtonDefaults.buttonColors(containerColor = GoldAccent)
                    ) {
                        Text("Retry")
                    }
                }
            }
        }
    }
}

package com.example.palmistry.data.local

import android.content.Context
import androidx.room.Database
import androidx.room.Room
import androidx.room.RoomDatabase
import com.example.palmistry.data.model.ReadingEntity

@Database(entities = [ReadingEntity::class], version = 1, exportSchema = false)
abstract class PalmistryDatabase : RoomDatabase() {

    abstract fun readingDao(): ReadingDao

    companion object {
        private const val DB_NAME = "palmistry_secure.db"

        @Volatile
        private var INSTANCE: PalmistryDatabase? = null

        fun getInstance(context: Context): PalmistryDatabase {
            return INSTANCE ?: synchronized(this) {
                val instance = Room.databaseBuilder(
                    context.applicationContext,
                    PalmistryDatabase::class.java,
                    DB_NAME
                )
                    .fallbackToDestructiveMigration()
                    .build()

                INSTANCE = instance
                instance
            }
        }
    }
}

